fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val graph = Array(n.toInt()) { LinkedList<Int>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        graph[u].add(v)
        graph[v].add(u)
